-- Generated by AutomateDV (formerly known as dbtvault)

    

WITH row_rank_1 AS (
    SELECT rr.ORDER_HK, rr.ORDER_ID, rr.LOAD_DATE, rr.RECORD_SOURCE
    FROM POC_DBT_PROJECT.UTILS_staging.stg_orders AS rr
    WHERE rr.ORDER_HK IS NOT NULL
    QUALIFY ROW_NUMBER() OVER(
        PARTITION BY rr.ORDER_HK
        ORDER BY rr.LOAD_DATE
    ) = 1
),

records_to_insert AS (
    SELECT a.ORDER_HK, a.ORDER_ID, a.LOAD_DATE, a.RECORD_SOURCE
    FROM row_rank_1 AS a
    LEFT JOIN POC_DBT_PROJECT.UTILS_raw_vault.hub_order AS d
    ON a.ORDER_HK = d.ORDER_HK
    WHERE d.ORDER_HK IS NULL
)

SELECT * FROM records_to_insert